package api

import (
	"net/http"

	"github.com/gin-gonic/gin"
)

func (s *Server) serveUsageControlPanel(c *gin.Context) {
	c.Data(http.StatusOK, "text/html; charset=utf-8", []byte(usageControlPanelHTML))
}

const usageControlPanelHTML = `<!doctype html>
<html lang="zh-CN">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>CLIProxyAPI Plus Usage</title>
<style>
:root{color-scheme:light dark;font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:#f6f7fb;color:#1f2937}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at top left,#fff 0,#f7f7fb 42%,#eef2ff 100%);color:#1f2937}.page{max-width:1240px;margin:0 auto;padding:26px}.header{display:flex;justify-content:space-between;gap:16px;align-items:center;margin-bottom:18px}.title h1{margin:0 0 6px;font-size:30px;letter-spacing:-.03em}.muted{color:#71717a}.actions{display:flex;gap:9px;flex-wrap:wrap;align-items:center}.btn{border:1px solid #e5e7eb;border-radius:11px;background:rgba(255,255,255,.86);color:#374151;padding:10px 14px;font:700 13px system-ui;cursor:pointer;text-decoration:none;box-shadow:0 8px 22px rgba(15,23,42,.05)}.btn.primary{background:#7c3aed;border-color:#7c3aed;color:#fff}.btn:disabled{opacity:.65;cursor:not-allowed}.updated{font-size:12px;color:#a1a1aa}.panel{background:rgba(255,255,255,.88);border:1px solid #e5e7eb;border-radius:18px;padding:16px;margin-bottom:16px;box-shadow:0 18px 45px rgba(15,23,42,.06);backdrop-filter:blur(10px)}.auth{display:none;border-color:#fde68a;background:#fffbeb;color:#92400e}.auth.show{display:block}.auth-row{display:flex;gap:8px;flex-wrap:wrap;margin-top:10px}.auth input{width:min(460px,100%);border:1px solid #d97706;border-radius:10px;padding:10px;background:#fff;color:#111827}.error{display:none;border-color:#fecaca;background:#fef2f2;color:#991b1b}.error.show{display:block}.filters{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.filters label{display:flex;flex-direction:column;gap:6px;font-size:12px;font-weight:800;color:#71717a}.filters input,.filters select{border:1px solid #e5e7eb;border-radius:11px;background:#fff;padding:10px;font:13px system-ui;color:#1f2937}.overview{display:grid;grid-template-columns:1.2fr 1.2fr 1fr;gap:16px;margin-bottom:16px}.metric{position:relative;min-height:214px;overflow:hidden}.metric:before{content:"";position:absolute;inset:0 0 auto;height:4px;background:var(--accent,#8b5cf6)}.metric.green{--accent:#22c55e}.metric.orange{--accent:#f97316}.metric.gray{--accent:#737373}.metric-head{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:14px}.metric-title{font-size:13px;font-weight:850;color:#8b8b91}.metric-icon{width:36px;height:36px;border-radius:10px;background:var(--accent,#8b5cf6);box-shadow:0 14px 26px color-mix(in srgb,var(--accent,#8b5cf6) 35%,transparent);display:grid;place-items:center;color:#fff;font-weight:900}.metric-value{font-size:34px;font-weight:900;letter-spacing:-.04em;margin-bottom:10px}.metric-sub{display:flex;gap:12px;flex-wrap:wrap;font-size:12px;color:#6b7280;margin-bottom:12px}.dot{display:inline-block;width:7px;height:7px;border-radius:999px;margin-right:5px;background:currentColor}.spark{width:100%;height:68px;border:1px solid #e5e7eb;border-radius:9px;background:#fafafa}.chart-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(360px,1fr));gap:16px;margin-bottom:16px}.chart-card h2,.table-wrap h2{margin:0 0 12px;font-size:17px}.chart-shell{height:280px;border:1px solid #e5e7eb;border-radius:12px;background:#fafafa;padding:10px}.chart-svg{width:100%;height:100%;display:block}.legend{display:flex;gap:12px;flex-wrap:wrap;margin-top:10px;font-size:12px;color:#6b7280}.legend i{display:inline-block;width:18px;height:3px;border-radius:999px;margin-right:6px;vertical-align:middle}.table-wrap{overflow:auto;background:rgba(255,255,255,.88);border:1px solid #e5e7eb;border-radius:18px;margin-bottom:16px;box-shadow:0 18px 45px rgba(15,23,42,.06)}.table-wrap h2{padding:16px 16px 0}.table{width:100%;border-collapse:collapse;font-size:13px;min-width:760px}.table th,.table td{padding:11px 16px;border-bottom:1px solid #e5e7eb;text-align:left;white-space:nowrap}.table th{font-size:12px;color:#71717a;background:#fafafa}.empty{height:100%;display:grid;place-items:center;color:#a1a1aa;font-size:13px}.axis{fill:#71717a;font-size:10px}.gridline{stroke:#e5e7eb;stroke-width:1}.line{fill:none;stroke-width:2.6;stroke-linecap:round;stroke-linejoin:round}.area{opacity:.11}.tooltip{position:fixed;display:none;pointer-events:none;background:#111827;color:#fff;border-radius:9px;padding:8px 10px;font-size:12px;box-shadow:0 12px 30px rgba(0,0,0,.2);z-index:10}@media (prefers-color-scheme:dark){:root,body{background:#020617;color:#e5e7eb}body{background:radial-gradient(circle at top left,#111827 0,#020617 60%)}.panel,.table-wrap,.btn,.filters input,.filters select{background:rgba(15,23,42,.9);color:#e5e7eb;border-color:#334155}.table th{background:#111827;color:#94a3b8}.muted,.updated,.metric-title,.metric-sub,.filters label,.legend{color:#94a3b8}.spark,.chart-shell{background:#0b1220;border-color:#334155}.gridline{stroke:#334155}.auth{background:#422006;color:#fde68a}.error{background:#450a0a;color:#fecaca}}@media (max-width:900px){.overview{grid-template-columns:1fr}.header{align-items:flex-start;flex-direction:column}.actions{width:100%}.btn{flex:1;text-align:center}.chart-grid{grid-template-columns:1fr}.page{padding:14px}}
</style>
</head>
<body>
<div class="page">
  <div class="header">
    <div class="title"><h1>使用统计</h1><div class="muted">CLIProxyAPI Plus usage 统计、Token 消耗、模型和 API Key 分布。</div></div>
    <div class="actions"><a class="btn" href="/management.html#/">Management</a><button class="btn" id="export">导出数据</button><button class="btn" id="import">导入数据</button><button class="btn primary" id="refresh">刷新</button><span class="updated" id="updated"></span></div>
  </div>
  <div id="auth" class="panel auth">请输入 Management Key 后查看 usage。密钥错误时这里会保持显示，可直接重新输入。<div class="auth-row"><input id="management-key" type="password" placeholder="Management key"><button class="btn primary" id="save-key">保存并刷新</button><button class="btn" id="clear-key">清除密钥</button></div></div>
  <div id="error" class="panel error"></div>
  <div class="panel filters">
    <label>时间范围<select id="quick-range"><option value="all">全部时间</option><option value="24h">最近 24 小时</option><option value="7d">最近 7 天</option><option value="30d">最近 30 天</option></select></label>
    <label>开始时间<input id="filter-start" type="datetime-local"></label>
    <label>结束时间<input id="filter-end" type="datetime-local"></label>
    <label>API Key<input id="filter-api-key" placeholder="your-api-key-3"></label>
    <label>Source<input id="filter-source" placeholder="source"></label>
    <label>Provider<input id="filter-provider" placeholder="mimo"></label>
    <label>Model<input id="filter-model" placeholder="mimo-v2.5-pro"></label>
  </div>
  <div id="overview" class="overview"></div>
  <div class="chart-grid">
    <div class="panel chart-card"><h2>总 Token 趋势</h2><div class="chart-shell" id="token-line"></div></div>
    <div class="panel chart-card"><h2>不同模型 Token 趋势</h2><div class="chart-shell" id="model-token-line"></div><div id="model-legend" class="legend"></div></div>
    <div class="panel chart-card"><h2>请求趋势</h2><div class="chart-shell" id="request-line"></div></div>
    <div class="panel chart-card"><h2>成功 / 失败请求</h2><div class="chart-shell" id="status-line"></div><div class="legend"><span><i style="background:#22c55e"></i>成功</span><span><i style="background:#ef4444"></i>失败</span></div></div>
  </div>
  <div class="table-wrap"><h2>Model Usage</h2><table class="table"><thead><tr><th>API/Source</th><th>Model</th><th>Requests</th><th>Tokens</th><th>Failed</th><th>Avg Latency</th><th>Last Seen</th></tr></thead><tbody id="model-rows"></tbody></table></div>
  <div class="table-wrap"><h2>API Key / Source Usage</h2><table class="table"><thead><tr><th>API Key / Source</th><th>Requests</th><th>Success</th><th>Failed</th><th>Tokens</th><th>Models</th></tr></thead><tbody id="api-key-rows"></tbody></table></div>
</div>
<div id="tooltip" class="tooltip"></div>
<input id="import-file" type="file" accept="application/json" style="display:none">
<script>
(function(){
  var tokenKey='cli-proxy-api:usage-page-management-key';
  var colors=['#8b5cf6','#22c55e','#f97316','#06b6d4','#ef4444','#eab308','#ec4899','#6366f1'];
  function el(id){return document.getElementById(id)}
  function fmt(n){return Number(n||0).toLocaleString()}
  function compact(n){n=Number(n||0);if(n>=1e9)return(n/1e9).toFixed(1).replace(/\.0$/,'')+'B';if(n>=1e6)return(n/1e6).toFixed(1).replace(/\.0$/,'')+'M';if(n>=1e3)return(n/1e3).toFixed(1).replace(/\.0$/,'')+'K';return fmt(n)}
  function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]})}
  function token(){return sessionStorage.getItem(tokenKey)||localStorage.getItem(tokenKey)||''}
  function showAuth(show){el('auth').classList.toggle('show',!!show);if(show)setTimeout(function(){el('management-key').focus()},0)}
  function clearToken(){sessionStorage.removeItem(tokenKey);localStorage.removeItem(tokenKey);showAuth(true)}
  function capture(v){v=String(v||'').trim();if(!v)return false;var m=v.match(/^Bearer\s+(.+)$/i);v=(m?m[1]:v).trim();sessionStorage.setItem(tokenKey,v);localStorage.setItem(tokenKey,v);showAuth(false);return true}
  function qs(params){var q=new URLSearchParams();Object.keys(params).forEach(function(k){var v=params[k];if(v!=null&&String(v).trim()!=='')q.set(k,String(v).trim())});var s=q.toString();return s?'?'+s:''}
  function filters(){function dt(id){var v=el(id).value;return v?new Date(v).toISOString():''}return{start:dt('filter-start'),end:dt('filter-end'),api_key:el('filter-api-key').value,source:el('filter-source').value,provider:el('filter-provider').value,model:el('filter-model').value}}
  function api(path,opt){var t=token();showAuth(!t);var h={'Accept':'application/json'};if(t)h.Authorization='Bearer '+t;if(opt&&opt.headers)Object.keys(opt.headers).forEach(function(k){h[k]=opt.headers[k]});return fetch(path,Object.assign({},opt||{},{headers:h})).then(function(r){if(r.status===401||r.status===403){clearToken();throw new Error('管理密钥无效，请重新输入 Management Key。')}if(!r.ok)throw new Error('请求失败: HTTP '+r.status);return r.json()})}
  function showError(msg){el('error').textContent=msg||'';el('error').classList.toggle('show',!!msg)}
  function bucketKey(ts,day){var d=new Date(ts);if(isNaN(d))return '';if(day)return d.toISOString().slice(0,10);return d.toISOString().slice(0,13).replace('T',' ')+':00'}
  function entries(map){return Object.keys(map||{}).sort().map(function(k){return{x:k,y:Number(map[k]||0)}})}
  function detailRows(u){var rows=[];Object.keys(u.apis||{}).forEach(function(api){var ms=(u.apis[api]||{}).models||{};Object.keys(ms).forEach(function(model){((ms[model]||{}).details||[]).forEach(function(d){rows.push(Object.assign({api:api,model:model},d))})})});return rows}
  function byDetails(rows,fn){var out={};rows.forEach(function(r){var k=fn(r);if(!k)return;out[k]=(out[k]||0)+1});return out}
  function tokenByDetails(rows,fn){var out={};rows.forEach(function(r){var k=fn(r);if(!k)return;out[k]=(out[k]||0)+Number((r.tokens&&r.tokens.total_tokens)||0)});return out}
  function overview(u,rows){var failed=Number(u.failure_count||0), success=Number(u.success_count||0), req=Number(u.total_requests||0), total=Number(u.total_tokens||0);var cached=rows.reduce(function(s,r){return s+Number((r.tokens&&r.tokens.cached_tokens)||0)},0);var reasoning=rows.reduce(function(s,r){return s+Number((r.tokens&&r.tokens.reasoning_tokens)||0)},0);var avg=rows.length?rows.reduce(function(s,r){return s+Number(r.latency_ms||0)},0)/rows.length/1000:0;var recent=rows.filter(function(r){return Date.now()-new Date(r.timestamp).getTime()<3600000}).length;var tseries=entries(u.tokens_by_day&&Object.keys(u.tokens_by_day).length?u.tokens_by_day:u.tokens_by_hour);var rseries=entries(u.requests_by_day&&Object.keys(u.requests_by_day).length?u.requests_by_day:u.requests_by_hour);el('overview').innerHTML=card('总请求数',compact(req),'<span><i class="dot" style="color:#22c55e"></i>成功请求: '+fmt(success)+'</span><span><i class="dot" style="color:#ef4444"></i>失败请求: '+fmt(failed)+'</span><span>平均延迟: '+avg.toFixed(2)+'秒</span>',rseries,'gray','⌘')+card('总Token数',compact(total),'<span>缓存 Tokens: '+compact(cached)+'</span><span>思考 Tokens: '+compact(reasoning)+'</span>',tseries,'','◇')+card('RPM',recent? (recent/60).toFixed(2):'0.00','<span>最近 1 小时请求数: '+fmt(recent)+'</span>',rseries.slice(-24),'green','↻')+card('TPM',recent? compact(tokenByDetails(rows.filter(function(r){return Date.now()-new Date(r.timestamp).getTime()<3600000}),function(){return 'x'}).x/60||0):'0','<span>最近 1 小时 Token 数: '+compact(tokenByDetails(rows.filter(function(r){return Date.now()-new Date(r.timestamp).getTime()<3600000}),function(){return 'x'}).x||0)+'</span>',tseries.slice(-24),'orange','↗')+card('总花费','--','<span>总Token数: '+compact(total)+'</span><span>请先设置模型价格</span>',[], 'gray','$')}
  function card(title,value,sub,series,klass,icon){return '<div class="panel metric '+klass+'"><div class="metric-head"><div><div class="metric-title">'+esc(title)+'</div></div><div class="metric-icon">'+esc(icon)+'</div></div><div class="metric-value">'+esc(value)+'</div><div class="metric-sub">'+sub+'</div>'+spark(series)+'</div>'}
  function spark(series){if(!series||!series.length)return '<div class="spark empty">暂无数据</div>';return '<div class="spark">'+svg([series],{mini:true,colors:['var(--accent,#8b5cf6)']})+'</div>'}
  function svg(series,opt){opt=opt||{};var w=760,h=opt.mini?66:250,p=opt.mini?8:34;var labels={};series.forEach(function(s){s.forEach(function(pt){labels[pt.x]=1})});var xs=Object.keys(labels).sort();if(!xs.length)return '<div class="empty">暂无数据</div>';var max=1;series.forEach(function(s){s.forEach(function(pt){if(pt.y>max)max=pt.y})});var xi={};xs.forEach(function(x,i){xi[x]=i});function X(x){return p+(xs.length===1?0:xi[x]*(w-p*2)/(xs.length-1))}function Y(y){return h-p-(Number(y||0)/max)*(h-p*2)}function path(s){return s.map(function(pt,i){return(i?'L':'M')+X(pt.x).toFixed(1)+' '+Y(pt.y).toFixed(1)}).join(' ')}var grid='';if(!opt.mini){for(var i=0;i<4;i++){var y=p+i*(h-p*2)/3;grid+='<line class="gridline" x1="'+p+'" y1="'+y+'" x2="'+(w-p)+'" y2="'+y+'"/>'}grid+='<text class="axis" x="'+p+'" y="16">'+compact(max)+'</text><text class="axis" x="'+p+'" y="'+(h-4)+'">0</text><text class="axis" x="'+(w-p-90)+'" y="'+(h-4)+'">'+esc(xs[xs.length-1])+'</text>'}var lines=series.map(function(s,i){var c=(opt.colors||colors)[i%(opt.colors||colors).length];return '<path class="line" d="'+path(s)+'" stroke="'+c+'"/>'}).join('');var dots=opt.mini?'':series.map(function(s,i){var c=(opt.colors||colors)[i%(opt.colors||colors).length];return s.map(function(pt){return '<circle cx="'+X(pt.x).toFixed(1)+'" cy="'+Y(pt.y).toFixed(1)+'" r="3" fill="'+c+'"><title>'+esc(pt.name||pt.x)+': '+fmt(pt.y)+'</title></circle>'}).join('')}).join('');return '<svg class="chart-svg" viewBox="0 0 '+w+' '+h+'" preserveAspectRatio="none">'+grid+lines+dots+'</svg>'}
  function renderLine(id,series,opt){el(id).innerHTML=series&&series.length?svg(series,opt):'<div class="empty">暂无数据</div>'}
  function renderCharts(u,rows){var useDay=(u.tokens_by_day&&Object.keys(u.tokens_by_day).length>1)||(rows.length&&new Date(rows[rows.length-1].timestamp)-new Date(rows[0].timestamp)>86400000);renderLine('token-line',[entries(u.tokens_by_day&&Object.keys(u.tokens_by_day).length?u.tokens_by_day:u.tokens_by_hour)],{colors:['#8b5cf6']});renderLine('request-line',[entries(u.requests_by_day&&Object.keys(u.requests_by_day).length?u.requests_by_day:u.requests_by_hour)],{colors:['#22c55e']});var ok=byDetails(rows,function(r){return r.failed?'':bucketKey(r.timestamp,useDay)}), bad=byDetails(rows,function(r){return r.failed?bucketKey(r.timestamp,useDay):''});renderLine('status-line',[entries(ok),entries(bad)],{colors:['#22c55e','#ef4444']});var byModel={};rows.forEach(function(r){var k=bucketKey(r.timestamp,useDay);if(!k)return;var m=r.model||'unknown';byModel[m]=byModel[m]||{};byModel[m][k]=(byModel[m][k]||0)+Number((r.tokens&&r.tokens.total_tokens)||0)});var modelNames=Object.keys(byModel).sort(function(a,b){var ta=Object.keys(byModel[a]).reduce(function(s,k){return s+byModel[a][k]},0),tb=Object.keys(byModel[b]).reduce(function(s,k){return s+byModel[b][k]},0);return tb-ta}).slice(0,6);renderLine('model-token-line',modelNames.map(function(m){return entries(byModel[m]).map(function(p){p.name=m+' '+p.x;return p})}),{colors:colors});el('model-legend').innerHTML=modelNames.map(function(m,i){return '<span><i style="background:'+colors[i%colors.length]+'"></i>'+esc(m)+'</span>'}).join('')}
  function models(u){var rows=[];Object.keys(u.apis||{}).forEach(function(api){var ms=(u.apis[api]||{}).models||{};Object.keys(ms).forEach(function(model){var m=ms[model]||{},details=m.details||[];var failed=details.filter(function(d){return d.failed}).length;var last=details.reduce(function(v,d){return d.timestamp&&d.timestamp>v?d.timestamp:v},'');var latency=details.length?details.reduce(function(s,d){return s+Number(d.latency_ms||0)},0)/details.length:0;rows.push({api:api,model:model,requests:m.total_requests||details.length,tokens:m.total_tokens||0,failed:failed,last:last,latency:latency})})});rows.sort(function(a,b){return b.tokens-a.tokens});el('model-rows').innerHTML=rows.length?rows.map(function(r){return '<tr><td>'+esc(r.api)+'</td><td>'+esc(r.model)+'</td><td>'+fmt(r.requests)+'</td><td>'+fmt(r.tokens)+'</td><td>'+fmt(r.failed)+'</td><td>'+((r.latency/1000)||0).toFixed(2)+'s</td><td>'+esc(r.last||'-')+'</td></tr>'}).join(''):'<tr><td colspan="7" class="muted">暂无数据</td></tr>'}
  function apiKeys(data){var keys=data.api_keys||{};var rows=Object.keys(keys).map(function(k){var v=keys[k]||{};return{key:k,requests:v.total_requests||0,success:v.success_count||0,failed:v.failure_count||0,tokens:v.total_tokens||0,models:Object.keys(v.models||{}).length}});rows.sort(function(a,b){return b.tokens-a.tokens});el('api-key-rows').innerHTML=rows.length?rows.map(function(r){return '<tr><td>'+esc(r.key)+'</td><td>'+fmt(r.requests)+'</td><td>'+fmt(r.success)+'</td><td>'+fmt(r.failed)+'</td><td>'+fmt(r.tokens)+'</td><td>'+fmt(r.models)+'</td></tr>'}).join(''):'<tr><td colspan="6" class="muted">暂无数据</td></tr>'}
  function load(){showError('');el('refresh').disabled=true;var query=qs(filters());Promise.all([api('/v0/management/usage'+query),api('/v0/management/api-key-usage'+query)]).then(function(res){var u=(res[0]&&res[0].usage)||{};var rows=detailRows(u).sort(function(a,b){return new Date(a.timestamp)-new Date(b.timestamp)});overview(u,rows);renderCharts(u,rows);models(u);apiKeys(res[1]||{});showAuth(false);el('updated').textContent='更新于: '+new Date().toLocaleTimeString()}).catch(function(e){showError(e&&e.message?e.message:String(e))}).finally(function(){el('refresh').disabled=false})}
  function applyQuickRange(){var v=el('quick-range').value;if(v==='all'){el('filter-start').value='';el('filter-end').value='';return}var now=new Date(),start=new Date(now);if(v==='24h')start.setHours(start.getHours()-24);if(v==='7d')start.setDate(start.getDate()-7);if(v==='30d')start.setDate(start.getDate()-30);function local(d){var z=new Date(d.getTime()-d.getTimezoneOffset()*60000);return z.toISOString().slice(0,16)}el('filter-start').value=local(start);el('filter-end').value=local(now)}
  el('save-key').onclick=function(){if(capture(el('management-key').value))load();else showAuth(true)};el('clear-key').onclick=function(){clearToken();showError('')};el('refresh').onclick=load;el('quick-range').onchange=function(){applyQuickRange();load()};['start','end','api-key','source','provider','model'].forEach(function(n){el('filter-'+n).addEventListener('change',load)});el('export').onclick=function(){location.href='/v0/management/usage/export'};el('import').onclick=function(){el('import-file').click()};el('import-file').onchange=function(){var f=this.files&&this.files[0];if(!f)return;f.text().then(function(text){return api('/v0/management/usage/import',{method:'POST',headers:{'Content-Type':'application/json'},body:text})}).then(load).catch(function(e){showError(e&&e.message?e.message:String(e))})};if(token())load();else showAuth(true);
})();
</script>
</body>
</html>`
